/// <summary>
/// Extension of the <c>SalesCopying_CreditNote</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(SalesCopying_CreditNote))]
final class SalesCopying_CreditNote_ETGSPAIN_Class_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>copyLine</c> method.
/// </summary>
/// <param name="_salesLine">SalesLine object.</param>
/// <param name="_salesLineCopyFromSource">SalesLineCopyFromSource object.</param>
protected void copyLine(SalesLine _salesLine, SalesLineCopyFromSource _salesLineCopyFromSource)
{
    next copyLine(_salesLine, _salesLineCopyFromSource);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (_salesLineCopyFromSource.parmTmpFrmVirtualLine().ETGSPAINHasUpdateUnsoldQty)
        {
            InventTrans                 inventTransCreated  = InventTrans::ETGSPAINcreateUnsoldInventTrans(InventTrans::findRecId(_salesLineCopyFromSource.parmTmpFrmVirtualLine().ETGSPAINUnsoldInventTransRefRecId));
            ETGSPAINUnsoldInventTrans   unsoldInventTrans   = ETGSPAINUnsoldInventTrans::findOrCreateByRefRecIdandQty(inventTransCreated.RecId,
                                                                                                                    0,
                                                                                                                    _salesLineCopyFromSource.parmSalesLine().SalesUnit,
                                                                                                                    _salesLineCopyFromSource.parmSalesLine(),
                                                                                                                    true);

            if (unsoldInventTrans)
            {
                ETGSPAINUnsoldInventTransModifyController::updateQty(unsoldInventTrans,
                                                                    abs(_salesLine.SalesQty),
                                                                    false);
            }
        }
    }
}
